import { useState, useEffect } from 'react';
import { getFriends, getFriendRequests, sendFriendRequest, acceptFriendRequest, removeFriend, searchUsers } from '../../../services/api';
import toast from 'react-hot-toast';

export default function GoSpace() {
  const [friends, setFriends] = useState([]);
  const [requests, setRequests] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [tab, setTab] = useState('friends');

  useEffect(() => {
    getFriends().then(r => setFriends(r.data));
    getFriendRequests().then(r => setRequests(r.data));
  }, []);

  useEffect(() => {
    if (searchQuery.length < 2) { setSearchResults([]); return; }
    const t = setTimeout(async () => {
      const res = await searchUsers(searchQuery);
      setSearchResults(res.data);
    }, 400);
    return () => clearTimeout(t);
  }, [searchQuery]);

  const handleAdd = async (userId) => {
    await sendFriendRequest(userId);
    toast.success('Friend request sent!');
  };

  const handleAccept = async (userId) => {
    await acceptFriendRequest(userId);
    getFriends().then(r => setFriends(r.data));
    getFriendRequests().then(r => setRequests(r.data));
    toast.success('Friend accepted!');
  };

  const handleRemove = async (userId) => {
    if (!window.confirm('Remove this friend?')) return;
    await removeFriend(userId);
    setFriends(prev => prev.filter(f => f.id !== userId));
    toast.success('Friend removed');
  };

  return (
    <div className="go-space">
      <div className="go-space-header">
        <h2>GoSpace</h2>
        <p>Connect with people on the platform</p>
      </div>

      <div className="search-users">
        <input
          placeholder="🔍 Search people..."
          value={searchQuery}
          onChange={e => setSearchQuery(e.target.value)}
          className="people-search"
        />
        {searchResults.length > 0 && (
          <div className="search-results-dropdown">
            {searchResults.map(u => (
              <div key={u.id} className="search-result-item">
                <div className="sr-avatar">{u.displayName?.[0]}</div>
                <div className="sr-info">
                  <div className="sr-name">{u.displayName}</div>
                  <div className="sr-username">@{u.username}</div>
                </div>
                <button className="add-btn" onClick={() => handleAdd(u.id)}>Add</button>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="go-space-tabs">
        <button className={`gs-tab ${tab === 'friends' ? 'active' : ''}`} onClick={() => setTab('friends')}>
          Friends ({friends.length})
        </button>
        <button className={`gs-tab ${tab === 'requests' ? 'active' : ''}`} onClick={() => setTab('requests')}>
          Requests {requests.length > 0 && <span className="req-badge">{requests.length}</span>}
        </button>
      </div>

      {tab === 'friends' && (
        <div className="friends-grid">
          {friends.length === 0 ? (
            <div className="empty-state">No friends yet. Search for people above!</div>
          ) : friends.map(f => (
            <div key={f.id} className="friend-card">
              <div className="friend-avatar">{f.displayName?.[0]}</div>
              <div className="friend-name">{f.displayName || f.username}</div>
              <div className={`friend-status ${f.isOnline ? 'online' : 'offline'}`}>
                {f.isOnline ? '● Online' : '○ Offline'}
              </div>
              <div className="friend-actions">
                <button className="msg-btn">Message</button>
                <button className="remove-btn" onClick={() => handleRemove(f.id)}>Remove</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {tab === 'requests' && (
        <div className="requests-list">
          {requests.length === 0 ? (
            <div className="empty-state">No pending requests</div>
          ) : requests.map(r => (
            <div key={r.id} className="request-item">
              <div className="req-avatar">{r.displayName?.[0]}</div>
              <div className="req-info">
                <div>{r.displayName || r.username}</div>
                <div className="req-sub">@{r.username}</div>
              </div>
              <div className="req-actions">
                <button className="accept-btn" onClick={() => handleAccept(r.id)}>Accept</button>
                <button className="decline-btn" onClick={() => handleRemove(r.id)}>Decline</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
